exercise.solution_code:
#include <iostream>
#include <iomanip>
#include <optional>

std::optional<double> averagePositive(const int* arr, int size) {
    double sum { 0.0 };
    int count { 0 };
    for (int i { 0 }; i < size; ++i) {
        if (arr[i] > 0) {
            sum += arr[i];
            ++count;
        }
    }
    if (count == 0)
        return std::nullopt;
    return sum / count;
}

int main() {
    int n{};
    std::cin >> n;

    int arr[10]{};
    for (int i { 0 }; i < n; ++i)
        std::cin >> arr[i];

    auto result { averagePositive(arr, n) };

    std::cout << std::fixed << std::setprecision(2);
    if (result.has_value())
        std::cout << "Average of positives: " << result.value() << '\n';
    else
        std::cout << "No positive elements\n";

    return 0;
}
